     if (match(V, m_SExt(m_Value(Op0))))
       V = Op0;
     else if (match(V, m_NNegZExt(m_Value(Op0)))) {
@@ -534,12 +535,22 @@ static Decomposition decompose(Value *V,
       return Result;
     }

+    if (match(V, m_NSWSub(m_Value(Op0), m_Value(Op1)))) {
