+      // Flip the sign of RHS by negating both A and B and adjusting the constraint accordingly.
+      RHS.CoefficientSign = -RHS.CoefficientSign;
+      RHS.IsKnownNonNegative = false; // Negation may make it negative.
+      return MergeResults(LHS, RHS, IsSigned);
+    }
+
     // (shl nsw x, shift) is (mul nsw x, (1<<shift)), with the exception of
     // shift == bw-1.
     if (match(V, m_NSWShl(m_Value(Op0), m_ConstantInt(CI)))) {
       uint64_t Shift = CI->getValue().getLimitedValue();
       if (Shift < Ty->getIntegerBitWidth() - 1) {
         assert(Shift < 64 && "Would overflow");
+
         auto Result = decompose(Op0, Preconditions, IsSigned, DL);
         Result.mul(int64_t(1) << Shift);
         return Result;

messages.content:
This is a missed-optimization in ConstraintElimination.

The following program reveals the missed optimization.
The source program is
```llvm
define i1 @test_decompose_sub_nsw_sgt_zero_inv(i32 %x, i32 %y) {
entry:
  %sub = sub nsw i32 %y, %x
  %cond = icmp sgt i32 %sub, 10
  br i1 %cond, label %if.then, label %if.else

if.then:                                          ; preds = %entry
  %ret = icmp sge i32 %x, %y
  ret i1 %ret

if.else:                                          ; preds = %entry
  ret i1 true
}

```

However, current LLVM cannot optimize the source program. The expected optimized program is
```llvm
define i1 @test_decompose_sub_nsw_sgt_zero_inv(i32 %x, i32 %y) {
entry:
  %sub = sub nsw i32 %y, %x
  %cond = icmp sgt i32 %sub, 10
  br i1 %cond, label %if.then, label %if.else

if.then:                                          ; preds = %entry
  ret i1 false

if.else:                                          ; preds = %entry
  ret i1 true
}

```
Please modify the following code in llvm/lib/Transforms/Scalar/ConstraintElimination.cpp:decompose to implement the missed optimization:
```cpp
    if (match(V, m_SExt(m_Value(Op0))))
      V = Op0;
    else if (match(V, m_NNegZExt(m_Value(Op0)))) {
      V = Op0;
      IsKnownNonNegative = true;
    } else if (match(V, m_NSWTrunc(m_Value(Op0)))) {
      if (Op0->getType()->getScalarSizeInBits() <= 64)
        V = Op0;
    }

    if (match(V, m_NSWAdd(m_Value(Op0), m_Value(Op1))))
      return MergeResults(Op0, Op1, IsSigned);

    ConstantInt *CI;
    if (match(V, m_NSWMul(m_Value(Op0), m_ConstantInt(CI))) && canUseSExt(CI)) {
      auto Result = decompose(Op0, Preconditions, IsSigned, DL);
      Result.mul(CI->getSExtValue());
      return Result;
    }

    // (shl nsw x, shift) is (mul nsw x, (1<<shift)), with the exception of
    // shift == bw-1.
    if (match(V, m_NSWShl(m_Value(Op0), m_ConstantInt(CI)))) {
      uint64_t Shift = CI->getValue().getLimitedValue();
      if (Shift < Ty->getIntegerBitWidth() - 1) {
        assert(Shift < 64 && "Would overflow");
```

